  1→import { Injectable } from '@nestjs/common';
  2→import { PrismaService } from '../prisma/prisma.service';
  3→import { RedisService } from '../redis/redis.service';
  4→import type {
  5→  AnalyticsOverview,
  6→  AnalyticsRange,
  7→  AgentBreakdown,
  8→  PageStats,
  9→  TimelinePoint,
 10→  PageAiInterest,
 11→  AiReferralOverview,
 12→  AiReferralStats,
 13→} from '@agent-analytics/types';
 14→import { AI_REFERRAL_DOMAINS } from '@agent-analytics/types';
 15→
 16→const RANGE_TO_INTERVAL: Record<AnalyticsRange, string> = {
 17→  '1d': '1 day',
 18→  '7d': '7 days',
 19→  '30d': '30 days',
 20→};
 21→
 22→const CACHE_TTL = 300; // 5 minutes
 23→
 24→@Injectable()
 25→export class AnalyticsService {
 26→  constructor(
 27→    private readonly prisma: PrismaService,
 28→    private readonly redis: RedisService,
 29→  ) {}
 30→
 31→  async getOverview(siteId: string, range: AnalyticsRange): Promise<AnalyticsOverview> {
 32→    const cacheKey = `overview:${siteId}:${range}`;
 33→
 34→    return this.redis.wrap(cacheKey, CACHE_TTL, async () => {
 35→      const interval = RANGE_TO_INTERVAL[range];
 36→
 37→      // Total, agent, human counts
 38→      const [stats] = await this.prisma.$queryRaw<
 39→        Array<{
 40→          total: bigint;
 41→          agents: bigint;
 42→          humans: bigint;
 43→          unique_agents: bigint;
 44→        }>
 45→      >`
 46→        SELECT
 47→          COUNT(*) as total,
 48→          COUNT(*) FILTER (WHERE is_agent = true) as agents,
 49→          COUNT(*) FILTER (WHERE is_agent = false) as humans,
 50→          COUNT(DISTINCT agent_name) FILTER (WHERE is_agent = true) as unique_agents
 51→        FROM events
 52→        WHERE site_id = ${siteId}
 53→          AND timestamp > NOW() - ${interval}::INTERVAL
 54→      `;
 55→
 56→      const total = Number(stats?.total ?? 0);
 57→      const agents = Number(stats?.agents ?? 0);
 58→      const humans = Number(stats?.humans ?? 0);
 59→      const uniqueAgents = Number(stats?.unique_agents ?? 0);
 60→
 61→      // Previous period cho change calculation
 62→      const [prevStats] = await this.prisma.$queryRaw<Array<{ agents: bigint }>>`
 63→        SELECT COUNT(*) FILTER (WHERE is_agent = true) as agents
 64→        FROM events
 65→        WHERE site_id = ${siteId}
 66→          AND timestamp > NOW() - (${interval}::INTERVAL * 2)
 67→          AND timestamp <= NOW() - ${interval}::INTERVAL
 68→      `;
 69→
 70→      const prevAgents = Number(prevStats?.agents ?? 0);
 71→      const agentChange = prevAgents > 0 ? ((agents - prevAgents) / prevAgents) * 100 : 0;
 72→
 73→      // Top agents
 74→      const topAgentsRaw = await this.prisma.$queryRaw<
 75→        Array<{ agent_name: string; count: bigint }>
 76→      >`
 77→        SELECT agent_name, COUNT(*) as count
 78→        FROM events
 79→        WHERE site_id = ${siteId}
 80→          AND is_agent = true
 81→          AND timestamp > NOW() - ${interval}::INTERVAL
 82→        GROUP BY agent_name
 83→        ORDER BY count DESC
 84→        LIMIT 10
 85→      `;
 86→
 87→      const topAgents: AgentBreakdown[] = topAgentsRaw.map((row) => ({
 88→        name: row.agent_name,
 89→        count: Number(row.count),
 90→        ratio: total > 0 ? (Number(row.count) / total) * 100 : 0,
 91→      }));
 92→
 93→      return {
 94→        totalRequests: total,
 95→        agentRequests: agents,
 96→        humanRequests: humans,
 97→        agentRatio: total > 0 ? (agents / total) * 100 : 0,
 98→        uniqueAgents,
 99→        agentChange: Math.round(agentChange * 100) / 100,
100→        topAgents,
101→      };
102→    });
103→  }
104→
105→  async getAgents(siteId: string, range: AnalyticsRange): Promise<AgentBreakdown[]> {
106→    const cacheKey = `agents:${siteId}:${range}`;
107→
108→    return this.redis.wrap(cacheKey, CACHE_TTL, async () => {
109→      const interval = RANGE_TO_INTERVAL[range];
110→
111→      const rows = await this.prisma.$queryRaw<
112→        Array<{ agent_name: string; count: bigint; total: bigint }>
113→      >`
114→        SELECT
115→          agent_name,
116→          COUNT(*) as count,
117→          (SELECT COUNT(*) FROM events WHERE site_id = ${siteId} AND timestamp > NOW() - ${interval}::INTERVAL) as total
118→        FROM events
119→        WHERE site_id = ${siteId}
120→          AND is_agent = true
121→          AND timestamp > NOW() - ${interval}::INTERVAL
122→        GROUP BY agent_name
123→        ORDER BY count DESC
124→      `;
125→
126→      return rows.map((row) => ({
127→        name: row.agent_name,
128→        count: Number(row.count),
129→        ratio: Number(row.total) > 0 ? (Number(row.count) / Number(row.total)) * 100 : 0,
130→      }));
131→    });
132→  }
133→
134→  async getPages(siteId: string, range: AnalyticsRange): Promise<PageStats[]> {
135→    const cacheKey = `pages:${siteId}:${range}`;
136→
137→    return this.redis.wrap(cacheKey, CACHE_TTL, async () => {
138→      const interval = RANGE_TO_INTERVAL[range];
139→
140→      const rows = await this.prisma.$queryRaw<
141→        Array<{ url: string; total: bigint; agents: bigint }>
142→      >`
143→        SELECT
144→          url,
145→          COUNT(*) as total,
146→          COUNT(*) FILTER (WHERE is_agent = true) as agents
147→        FROM events
148→        WHERE site_id = ${siteId}
149→          AND timestamp > NOW() - ${interval}::INTERVAL
150→        GROUP BY url
151→        ORDER BY agents DESC
152→        LIMIT 50
153→      `;
154→
155→      return rows.map((row) => ({
156→        url: row.url,
157→        totalRequests: Number(row.total),
158→        agentRequests: Number(row.agents),
159→        agentRatio: Number(row.total) > 0 ? (Number(row.agents) / Number(row.total)) * 100 : 0,
160→      }));
161→    });
162→  }
163→
164→  async getTimeline(siteId: string, range: AnalyticsRange): Promise<TimelinePoint[]> {
165→    const cacheKey = `timeline:${siteId}:${range}`;
166→
167→    return this.redis.wrap(cacheKey, CACHE_TTL, async () => {
168→      const interval = RANGE_TO_INTERVAL[range];
169→      // Group by hour for 1d, by day for 7d/30d
170→      const bucket = range === '1d' ? 'hour' : 'day';
171→
172→      const rows = await this.prisma.$queryRaw<
173→        Array<{ bucket: Date; total: bigint; agents: bigint; humans: bigint }>
174→      >`
175→        SELECT
176→          date_trunc(${bucket}, timestamp) as bucket,
177→          COUNT(*) as total,
178→          COUNT(*) FILTER (WHERE is_agent = true) as agents,
179→          COUNT(*) FILTER (WHERE is_agent = false) as humans
180→        FROM events
181→        WHERE site_id = ${siteId}
182→          AND timestamp > NOW() - ${interval}::INTERVAL
183→        GROUP BY bucket
184→        ORDER BY bucket ASC
185→      `;
186→
187→      return rows.map((row) => ({
188→        timestamp: row.bucket.toISOString(),
189→        total: Number(row.total),
190→        agents: Number(row.agents),
191→        humans: Number(row.humans),
192→      }));
193→    });
194→  }
195→
196→  async getPagesAiInterest(
197→    siteId: string,
198→    range: AnalyticsRange,
199→    limit: number,
200→  ): Promise<{ pages: PageAiInterest[]; total: number }> {
201→    const cacheKey = `pages-ai:${siteId}:${range}:${limit}`;
202→
203→    return this.redis.wrap(cacheKey, CACHE_TTL, async () => {
204→      const interval = RANGE_TO_INTERVAL[range];
205→
206→      // Page-level AI visits with agent type breakdown
207→      const rows = await this.prisma.$queryRaw<
208→        Array<{
209→          url: string;
210→          ai_visits: bigint;
211→          unique_agents: bigint;
212→          training: bigint;
213→          search: bigint;
214→          on_demand: bigint;
215→        }>
216→      >`
217→        SELECT
218→          url,
219→          COUNT(*) as ai_visits,
220→          COUNT(DISTINCT agent_name) as unique_agents,
221→          COUNT(*) FILTER (WHERE agent_type = 'training') as training,
222→          COUNT(*) FILTER (WHERE agent_type = 'search') as search,
223→          COUNT(*) FILTER (WHERE agent_type = 'on_demand') as on_demand
224→        FROM events
225→        WHERE site_id = ${siteId}
226→          AND is_agent = true
227→          AND timestamp > NOW() - ${interval}::INTERVAL
228→        GROUP BY url
229→        ORDER BY ai_visits DESC
230→        LIMIT ${limit}
231→      `;
232→
233→      // Previous period for trend calculation
234→      const prevRows = await this.prisma.$queryRaw<
235→        Array<{ url: string; ai_visits: bigint }>
236→      >`
237→        SELECT url, COUNT(*) as ai_visits
238→        FROM events
239→        WHERE site_id = ${siteId}
240→          AND is_agent = true
241→          AND timestamp > NOW() - (${interval}::INTERVAL * 2)
242→          AND timestamp <= NOW() - ${interval}::INTERVAL
243→        GROUP BY url
244→      `;
245→
246→      const prevMap = new Map(
247→        prevRows.map((r) => [r.url, Number(r.ai_visits)]),
248→      );
249→
250→      // Top agents per page (batch query)
251→      const urls = rows.map((r) => r.url);
252→      const topAgentsRows = urls.length > 0
253→        ? await this.prisma.$queryRaw<
254→            Array<{ url: string; agent_name: string; count: bigint }>
255→          >`
256→            SELECT url, agent_name, COUNT(*) as count
257→            FROM events
258→            WHERE site_id = ${siteId}
259→              AND is_agent = true
260→              AND timestamp > NOW() - ${interval}::INTERVAL
261→              AND url = ANY(${urls})
262→            GROUP BY url, agent_name
263→            ORDER BY url, count DESC
264→          `
265→        : [];
266→
267→      // Group top agents by URL (keep top 5 per page)
268→      const agentsByUrl = new Map<string, AgentBreakdown[]>();
269→      for (const row of topAgentsRows) {
270→        const list = agentsByUrl.get(row.url) ?? [];
271→        if (list.length < 5) {
272→          list.push({
273→            name: row.agent_name,
274→            count: Number(row.count),
275→            ratio: 0, // calculated below
276→          });
277→          agentsByUrl.set(row.url, list);
278→        }
279→      }
280→
281→      // Total count for pagination meta
282→      const [countResult] = await this.prisma.$queryRaw<Array<{ total: bigint }>>`
283→        SELECT COUNT(DISTINCT url) as total
284→        FROM events
285→        WHERE site_id = ${siteId}
286→          AND is_agent = true
287→          AND timestamp > NOW() - ${interval}::INTERVAL
288→      `;
289→
290→      const pages: PageAiInterest[] = rows.map((row) => {
291→        const aiVisits = Number(row.ai_visits);
292→        const prev = prevMap.get(row.url) ?? 0;
293→        const trend = prev > 0 ? ((aiVisits - prev) / prev) * 100 : (aiVisits > 0 ? 100 : 0);
294→
295→        const pageAgents = agentsByUrl.get(row.url) ?? [];
296→        for (const agent of pageAgents) {
297→          agent.ratio = aiVisits > 0 ? (agent.count / aiVisits) * 100 : 0;
298→        }
299→
300→        return {
301→          url: row.url,
302→          aiVisits,
303→          uniqueAgents: Number(row.unique_agents),
304→          topAgents: pageAgents,
305→          trend: Math.round(trend * 100) / 100,
306→          agentTypes: {
307→            training: Number(row.training),
308→            search: Number(row.search),
309→            on_demand: Number(row.on_demand),
310→          },
311→        };
312→      });
313→
314→      return { pages, total: Number(countResult?.total ?? 0) };
315→    });
316→  }
317→
318→  async getReferrals(
319→    siteId: string,
320→    range: AnalyticsRange,
321→  ): Promise<AiReferralOverview> {
322→    const cacheKey = `referrals:${siteId}:${range}`;
323→
324→    return this.redis.wrap(cacheKey, CACHE_TTL, async () => {
325→      const interval = RANGE_TO_INTERVAL[range];
326→
327→      // Total traffic for share calculation
328→      const [totalResult] = await this.prisma.$queryRaw<Array<{ total: bigint }>>`
329→        SELECT COUNT(*) as total
330→        FROM events
331→        WHERE site_id = ${siteId}
332→          AND timestamp > NOW() - ${interval}::INTERVAL
333→      `;
334→      const totalTraffic = Number(totalResult?.total ?? 0);
335→
336→      // AI referral sources
337→      const rows = await this.prisma.$queryRaw<
338→        Array<{
339→          referrer_domain: string;
340→          visits: bigint;
341→          unique_pages: bigint;
342→          top_landing: string;
343→        }>
344→      >`
345→        SELECT
346→          referrer_domain,
347→          COUNT(*) as visits,
348→          COUNT(DISTINCT url) as unique_pages,
349→          (
350→            SELECT url FROM events e2
351→            WHERE e2.site_id = ${siteId}
352→              AND e2.referrer_domain = e.referrer_domain
353→              AND e2.referrer_type = 'ai_referral'
354→              AND e2.timestamp > NOW() - ${interval}::INTERVAL
355→            GROUP BY url
356→            ORDER BY COUNT(*) DESC
357→            LIMIT 1
358→          ) as top_landing
359→        FROM events e
360→        WHERE site_id = ${siteId}
361→          AND referrer_type = 'ai_referral'
362→          AND referrer_domain IS NOT NULL
363→          AND timestamp > NOW() - ${interval}::INTERVAL
364→        GROUP BY referrer_domain
365→        ORDER BY visits DESC
366→      `;
367→
368→      // Previous period for trends
369→      const prevRows = await this.prisma.$queryRaw<
370→        Array<{ referrer_domain: string; visits: bigint }>
371→      >`
372→        SELECT referrer_domain, COUNT(*) as visits
373→        FROM events
374→        WHERE site_id = ${siteId}
375→          AND referrer_type = 'ai_referral'
376→          AND referrer_domain IS NOT NULL
377→          AND timestamp > NOW() - (${interval}::INTERVAL * 2)
378→          AND timestamp <= NOW() - ${interval}::INTERVAL
379→        GROUP BY referrer_domain
380→      `;
381→
382→      const prevMap = new Map(
383→        prevRows.map((r) => [r.referrer_domain, Number(r.visits)]),
384→      );
385→
386→      const sources: AiReferralStats[] = rows.map((row) => {
387→        const visits = Number(row.visits);
388→        const prev = prevMap.get(row.referrer_domain) ?? 0;
389→        const trend = prev > 0 ? ((visits - prev) / prev) * 100 : (visits > 0 ? 100 : 0);
390→
391→        return {
392→          source: AI_REFERRAL_DOMAINS[row.referrer_domain] ?? row.referrer_domain,
393→          referrerDomain: row.referrer_domain,
394→          visits,
395→          uniquePages: Number(row.unique_pages),
396→          topLandingPage: row.top_landing ?? '',
397→          trend: Math.round(trend * 100) / 100,
398→        };
399→      });
400→
401→      const totalReferrals = sources.reduce((sum, s) => sum + s.visits, 0);
402→
403→      return {
404→        sources,
405→        totalReferrals,
406→        referralShare: totalTraffic > 0
407→          ? Math.round((totalReferrals / totalTraffic) * 10000) / 100
408→          : 0,
409→      };
410→    });
411→  }
412→}
