 1→import { Controller, Get, Query, UseGuards } from '@nestjs/common';
 2→import { AnalyticsService } from './analytics.service';
 3→import { JwtAuthGuard } from '../auth/guards/jwt-auth.guard';
 4→import { AnalyticsQueryDto } from './dto/analytics-query.dto';
 5→import { PrismaService } from '../prisma/prisma.service';
 6→
 7→/** Plan-based page limits for ai-interest endpoint */
 8→const PAGE_LIMITS: Record<string, number> = {
 9→  free: 10,
10→  starter: 50,
11→  pro: 500,
12→  business: 500,
13→};
14→
15→@Controller('analytics')
16→@UseGuards(JwtAuthGuard)
17→export class AnalyticsController {
18→  constructor(
19→    private readonly analyticsService: AnalyticsService,
20→    private readonly prisma: PrismaService,
21→  ) {}
22→
23→  @Get('overview')
24→  async getOverview(@Query() query: AnalyticsQueryDto) {
25→    const data = await this.analyticsService.getOverview(query.siteId, query.range);
26→    return { data };
27→  }
28→
29→  @Get('agents')
30→  async getAgents(@Query() query: AnalyticsQueryDto) {
31→    const data = await this.analyticsService.getAgents(query.siteId, query.range);
32→    return { data };
33→  }
34→
35→  @Get('pages')
36→  async getPages(@Query() query: AnalyticsQueryDto) {
37→    const data = await this.analyticsService.getPages(query.siteId, query.range);
38→    return { data };
39→  }
40→
41→  @Get('timeline')
42→  async getTimeline(@Query() query: AnalyticsQueryDto) {
43→    const data = await this.analyticsService.getTimeline(query.siteId, query.range);
44→    return { data };
45→  }
46→
47→  @Get('pages/ai-interest')
48→  async getPagesAiInterest(@Query() query: AnalyticsQueryDto) {
49→    const site = await this.prisma.site.findUnique({
50→      where: { id: query.siteId },
51→      select: { plan: true },
52→    });
53→    const plan = (site?.plan ?? 'free') as string;
54→    const limit = PAGE_LIMITS[plan] ?? 10;
55→
56→    const result = await this.analyticsService.getPagesAiInterest(
57→      query.siteId,
58→      query.range,
59→      limit,
60→    );
61→    return { data: result.pages, meta: { total: result.total, limit } };
62→  }
63→
64→  @Get('referrals')
65→  async getReferrals(@Query() query: AnalyticsQueryDto) {
66→    const data = await this.analyticsService.getReferrals(query.siteId, query.range);
67→    return { data };
68→  }
69→}
