 1→import { IsString, IsEnum } from 'class-validator';
 2→import type { AnalyticsRange } from '@agent-analytics/types';
 3→
 4→export class AnalyticsQueryDto {
 5→  @IsString()
 6→  siteId!: string;
 7→
 8→  @IsEnum(['1d', '7d', '30d'])
 9→  range!: AnalyticsRange;
10→}
