 1→import { NestFactory } from '@nestjs/core';
 2→import { FastifyAdapter, NestFastifyApplication } from '@nestjs/platform-fastify';
 3→import { ValidationPipe } from '@nestjs/common';
 4→import { ConfigService } from '@nestjs/config';
 5→import { AppModule } from './app.module';
 6→
 7→async function bootstrap() {
 8→  const app = await NestFactory.create<NestFastifyApplication>(
 9→    AppModule,
10→    new FastifyAdapter({ logger: true }),
11→  );
12→
13→  app.useGlobalPipes(
14→    new ValidationPipe({
15→      whitelist: true,
16→      forbidNonWhitelisted: true,
17→      transform: true,
18→    }),
19→  );
20→
21→  app.enableCors({
22→    origin: true,
23→    credentials: true,
24→  });
25→
26→  const configService = app.get(ConfigService);
27→  const port = configService.get<number>('PORT', 3002);
28→
29→  await app.listen(port, '0.0.0.0');
30→}
31→
32→bootstrap();
