 1→import { Injectable, NotFoundException, ForbiddenException } from '@nestjs/common';
 2→import { ConfigService } from '@nestjs/config';
 3→import { randomBytes } from 'crypto';
 4→import { PrismaService } from '../prisma/prisma.service';
 5→import { PLAN_LIMITS, type PlanType } from '@agent-analytics/types';
 6→import { CreateSiteDto } from './dto/create-site.dto';
 7→
 8→@Injectable()
 9→export class SitesService {
10→  constructor(
11→    private readonly prisma: PrismaService,
12→    private readonly configService: ConfigService,
13→  ) {}
14→
15→  async findAllByUser(userId: string) {
16→    return this.prisma.site.findMany({
17→      where: { userId },
18→      orderBy: { createdAt: 'desc' },
19→    });
20→  }
21→
22→  async create(userId: string, dto: CreateSiteDto) {
23→    // Check plan limit for number of sites
24→    const currentSites = await this.prisma.site.count({ where: { userId } });
25→    const user = await this.prisma.user.findUnique({ where: { id: userId } });
26→
27→    // Get plan from first site (simplified — production will have user plan)
28→    const firstSite = await this.prisma.site.findFirst({ where: { userId } });
29→    const plan = (firstSite?.plan ?? 'free') as PlanType;
30→    const maxSites = PLAN_LIMITS[plan].sites;
31→
32→    if (currentSites >= maxSites) {
33→      throw new ForbiddenException(`Plan ${plan} allows max ${maxSites} sites`);
34→    }
35→
36→    const apiKey = this.generateApiKey();
37→
38→    return this.prisma.site.create({
39→      data: {
40→        userId,
41→        domain: dto.domain,
42→        apiKey,
43→      },
44→    });
45→  }
46→
47→  async getSnippet(siteId: string, userId: string): Promise<string> {
48→    const site = await this.findOneOrFail(siteId, userId);
49→    const trackerUrl = this.configService.get<string>(
50→      'TRACKER_CDN_URL',
51→      'https://cdn.agentanalytics.io/tracker.js',
52→    );
53→
54→    return `<script async src="${trackerUrl}" data-site="${site.apiKey}"></script>`;
55→  }
56→
57→  async rotateApiKey(siteId: string, userId: string) {
58→    await this.findOneOrFail(siteId, userId);
59→
60→    const newApiKey = this.generateApiKey();
61→    return this.prisma.site.update({
62→      where: { id: siteId },
63→      data: { apiKey: newApiKey },
64→    });
65→  }
66→
67→  private async findOneOrFail(siteId: string, userId: string) {
68→    const site = await this.prisma.site.findUnique({ where: { id: siteId } });
69→    if (!site) {
70→      throw new NotFoundException('Site not found');
71→    }
72→    if (site.userId !== userId) {
73→      throw new ForbiddenException('Access denied');
74→    }
75→    return site;
76→  }
77→
78→  private generateApiKey(): string {
79→    return `aa_${randomBytes(24).toString('hex')}`;
80→  }
81→}
