  1→import { Injectable } from '@nestjs/common';
  2→import { PrismaService } from '../prisma/prisma.service';
  3→import { RedisService } from '../redis/redis.service';
  4→import type {
  5→  AnalyticsOverview,
  6→  AnalyticsRange,
  7→  AgentBreakdown,
  8→  PageStats,
  9→  TimelinePoint,
 10→  PageAiInterest,
 11→  AiReferralOverview,
 12→  AiReferralStats,
 13→} from '@agent-analytics/types';
 14→import { AI_REFERRAL_DOMAINS } from '@agent-analytics/types';
 15→
 16→const RANGE_TO_INTERVAL: Record<AnalyticsRange, string> = {
 17→  '1d': '1 day',
 18→  '7d': '7 days',
 19→  '30d': '30 days',
 20→};
 21→
 22→const CACHE_TTL = 300; // 5 minutes
 23→
 24→@Injectable()
 25→export class AnalyticsService {
 26→  constructor(
 27→    private readonly prisma: PrismaService,
 28→    private readonly redis: RedisService,
 29→  ) {}
 30→
 31→  async getOverview(siteId: string, range: AnalyticsRange): Promise<AnalyticsOverview> {
 32→    const cacheKey = `overview:${siteId}:${range}`;
 33→
 34→    return this.redis.wrap(cacheKey, CACHE_TTL, async () => {
 35→      const interval = RANGE_TO_INTERVAL[range];
 36→
 37→      // Total, agent, human counts
 38→      const [stats] = await this.prisma.$queryRaw<
 39→        Array<{
 40→          total: bigint;
 41→          agents: bigint;
 42→          humans: bigint;
 43→          unique_agents: bigint;
 44→        }>
 45→      >`
 46→        SELECT
 47→          COUNT(*) as total,
 48→          COUNT(*) FILTER (WHERE is_agent = true) as agents,
 49→          COUNT(*) FILTER (WHERE is_agent = false) as humans,
 50→          COUNT(DISTINCT agent_name) FILTER (WHERE is_agent = true) as unique_agents
 51→        FROM events
 52→        WHERE site_id = ${siteId}
 53→          AND timestamp > NOW() - ${interval}::INTERVAL
 54→      `;
 55→
 56→      const total = Number(stats?.total ?? 0);
 57→      const agents = Number(stats?.agents ?? 0);
 58→      const humans = Number(stats?.humans ?? 0);
 59→      const uniqueAgents = Number(stats?.unique_agents ?? 0);
 60→
 61→      // Previous period cho change calculation
 62→      const [prevStats] = await this.prisma.$queryRaw<Array<{ agents: bigint }>>`
 63→        SELECT COUNT(*) FILTER (WHERE is_agent = true) as agents
 64→        FROM events
 65→        WHERE site_id = ${siteId}
 66→          AND timestamp > NOW() - (${interval}::INTERVAL * 2)
 67→          AND timestamp <= NOW() - ${interval}::INTERVAL
 68→      `;
 69→
 70→      const prevAgents = Number(prevStats?.agents ?? 0);
 71→      const agentChange = prevAgents > 0 ? ((agents - prevAgents) / prevAgents) * 100 : 0;
 72→
 73→      // Top agents
 74→      const topAgentsRaw = await this.prisma.$queryRaw<
 75→        Array<{ agent_name: string; count: bigint }>
 76→      >`
 77→        SELECT agent_name, COUNT(*) as count
 78→        FROM events
 79→        WHERE site_id = ${siteId}
 80→          AND is_agent = true
 81→          AND timestamp > NOW() - ${interval}::INTERVAL
 82→        GROUP BY agent_name
 83→        ORDER BY count DESC
 84→        LIMIT 10
 85→      `;
 86→
 87→      const topAgents: AgentBreakdown[] = topAgentsRaw.map((row) => ({
 88→        name: row.agent_name,
 89→        count: Number(row.count),
 90→        ratio: total > 0 ? (Number(row.count) / total) * 100 : 0,
 91→      }));
 92→
 93→      return {
 94→        totalRequests: total,
 95→        agentRequests: agents,
 96→        humanRequests: humans,
 97→        agentRatio: total > 0 ? (agents / total) * 100 : 0,
 98→        uniqueAgents,
 99→        agentChange: Math.round(agentChange * 100) / 100,
100→        topAgents,
101→      };
102→    });
103→  }
104→
105→  async getAgents(siteId: string, range: AnalyticsRange): Promise<AgentBreakdown[]> {
106→    const cacheKey = `agents:${siteId}:${range}`;
107→
108→    return this.redis.wrap(cacheKey, CACHE_TTL, async () => {
109→      const interval = RANGE_TO_INTERVAL[range];
110→
111→      const rows = await this.prisma.$queryRaw<
112→        Array<{ agent_name: string; count: bigint; total: bigint }>
113→      >`
114→        SELECT
115→          agent_name,
116→          COUNT(*) as count,
117→          (SELECT COUNT(*) FROM events WHERE site_id = ${siteId} AND timestamp > NOW() - ${interval}::INTERVAL) as total
118→        FROM events
119→        WHERE site_id = ${siteId}
120→          AND is_agent = true
121→          AND timestamp > NOW() - ${interval}::INTERVAL
122→        GROUP BY agent_name
123→        ORDER BY count DESC
124→      `;
125→
126→      return rows.map((row) => ({
127→        name: row.agent_name,
128→        count: Number(row.count),
129→        ratio: Number(row.total) > 0 ? (Number(row.count) / Number(row.total)) * 100 : 0,
130→      }));
131→    });
132→  }
133→
134→  async getPages(siteId: string, range: AnalyticsRange): Promise<PageStats[]> {
135→    const cacheKey = `pages:${siteId}:${range}`;
136→
