 1→const API_BASE = import.meta.env.VITE_API_URL || '/api';
 2→
 3→async function request<T>(path: string, options?: RequestInit): Promise<T> {
 4→  const token = localStorage.getItem('aa_token');
 5→
 6→  const res = await fetch(`${API_BASE}${path}`, {
 7→    ...options,
 8→    headers: {
 9→      'Content-Type': 'application/json',
10→      ...(token ? { Authorization: `Bearer ${token}` } : {}),
11→      ...options?.headers,
12→    },
13→  });
14→
15→  if (!res.ok) {
16→    const error = await res.json().catch(() => ({ message: 'Request failed' }));
17→    throw new Error(error.message || `HTTP ${res.status}`);
18→  }
19→
20→  return res.json();
21→}
22→
23→export const api = {
