import { NestFactory } from '@nestjs/core';
import { FastifyAdapter, NestFastifyApplication } from '@nestjs/platform-fastify';
import { ValidationPipe } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { AppModule } from './app.module';

async function bootstrap() {
  const app = await NestFactory.create<NestFastifyApplication>(
    AppModule,
    new FastifyAdapter({ logger: true }),
  );

  // Preserve raw body for Stripe webhook signature verification
  const fastifyInstance = app.getHttpAdapter().getInstance();
  fastifyInstance.addContentTypeParser(
    'application/json',
    { parseAs: 'buffer' },
    (
      _req: { headers: Record<string, string | undefined> },
      body: Buffer,
      done: (err: null, result: unknown) => void,
    ) => {
      // Store raw body for webhook routes, parse JSON for all others
      if (
        _req.headers['stripe-signature']
      ) {
        (_req as Record<string, unknown>).rawBody = body;
        done(null, JSON.parse(body.toString()));
      } else {
        done(null, JSON.parse(body.toString()));
      }
    },
  );

  app.useGlobalPipes(
    new ValidationPipe({
      whitelist: true,
      forbidNonWhitelisted: true,
      transform: true,
    }),
  );

  app.enableCors({
    origin: true,
    credentials: true,
  });

  const configService = app.get(ConfigService);
  const port = configService.get<number>('PORT', 3002);

  await app.listen(port, '0.0.0.0');
}

bootstrap();

