              {plan.highlight && (
                <span className="self-start px-3 py-1 text-xs font-semibold text-brand-700 dark:text-brand-400 bg-brand-50 dark:bg-brand-900/20 rounded-full mb-4">
                  Most Popular
                </span>
              )}

